export function getTypeDescription(code: string): TypeDescription | undefined {
  return TYPE_DESCRIPTIONS.find(t => t.code === code);
}

export function getTypesByBaseType(baseType: string): TypeDescription[] {
  return TYPE_DESCRIPTIONS.filter(t => t.code.startsWith(baseType + "-"));
}

export function getTypesByLayer(layer: number): TypeDescription[] {
  return TYPE_DESCRIPTIONS.filter(t => t.code.endsWith("-L" + layer));
}
